def keep_features_dicts_synced(func):
    """
    Wrapper to keep the secondary dictionary, `_column_requires_decoding`, of the `Features` class in sync with the
    main dictionary. This is required since we forbid direct mutation of `_column_requires_decoding` and require
    that all dictionary operations (`__setitem__`, `__delitem__`, `update`, `pop`, `popitem`, `setdefault`,
    `clear`, ...) go through the main dictionary, from which `_column_requires_decoding` is then recomputed.

    A decorator is used here instead of subclassing `collections.UserDict` for performance reasons: `UserDict`
    stores its data in a plain (non-subclassed) `dict` under `self.data`, which requires all methods to be
    reimplemented and adds a layer of indirection on every access.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self: "Features" = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper._decorator_name_ = "keep_features_dicts_synced"
    return wrapper


